import re
from dataclasses import dataclass

@dataclass
class PSEvalResult:
    question: str
    response: str
    has_plan: bool          # numbered list before first calculation
    has_variables: bool     # variable extraction block present
    final_answer: str | None
    correct: bool | None    # None if ground truth not provided

def extract_final_answer(response: str) -> str | None:
    """Extract the final numeric or text answer from a PS response."""
    # Look for "Answer:" label
    m = re.search(r"(?i)answer:\s*(.+)", response)
    if m:
        return m.group(1).strip()
    # Fall back to last line
    lines = [l.strip() for l in response.splitlines() if l.strip()]
    return lines[-1] if lines else None

def evaluate_ps_response(question: str, response: str,
                         ground_truth: str | None = None) -> PSEvalResult:
    # Check plan presence: at least two numbered items before any = sign
    plan_match = re.search(r"(\d\..*\n){2,}", response)
    has_plan = bool(plan_match and plan_match.start() < response.find("="))

    # Check variable block
    has_vars = bool(re.search(
        r"(?i)(variable|given|known|let)s?:\s*\n", response
    ))

    answer = extract_final_answer(response)
    correct = None
    if ground_truth and answer:
        # Normalize: strip units, compare numerically if possible
        def normalize(s):
            nums = re.findall(r"-?\d+\.?\d*", s)
            return nums[-1] if nums else s.lower().strip()
        correct = normalize(answer) == normalize(ground_truth)

    return PSEvalResult(
        question=question, response=response,
        has_plan=has_plan, has_variables=has_vars,
        final_answer=answer, correct=correct,
    )

def batch_evaluate(qa_pairs: list[tuple[str, str]], chain) -> dict:
    results = [evaluate_ps_response(q, chain.invoke({"question": q}), gt)
               for q, gt in qa_pairs]
    return {
        "accuracy": sum(r.correct for r in results if r.correct is not None) / len(results),
        "plan_compliance": sum(r.has_plan for r in results) / len(results),
        "variable_compliance": sum(r.has_variables for r in results) / len(results),
    }
